// ─── MEME FORGE ────────────────────────────────────────────────────────────────
function MemeModule() {
  const [topic, setTopic] = useState("");
  const [loading, setLoading] = useState(false);
  const [memes, setMemes] = useState([]);

  const quickTopics = ["Semester exams", "College WiFi", "CGPA", "Viva voce", "Lab records", "Placement season", "Professor bunk"];

  async function generateMemes(t = topic) {
    if (!t.trim()) return;
    setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          messages: [{
            role: "user",
            content: `Generate 3 funny engineering student memes about "${t}". Use classic meme formats. Mix Hindi/English (Hinglish). Format as JSON array only, no markdown:
[
  {"format": "Drake Pointing", "top": "...", "bottom": "..."},
  {"format": "Distracted Boyfriend", "boyfriend": "...", "girlfriend": "...", "other_girl": "..."},
  {"format": "This is fine dog", "caption": "..."}
]`
          }]
        })
      });
      const data = await res.json();
      const text = data.content?.[0]?.text || "[]";
      const clean = text.replace(/```json|```/g, "").trim();
      const parsed = JSON.parse(clean);
      setMemes(parsed);
    } catch (e) {
      setMemes([{ format: "Error", top: "Kuch toh gadbad hai", bottom: e.message }]);
    }
    setLoading(false);
  }

  return (
    <div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 16 }}>
        {quickTopics.map(t => (
          <button key={t} onClick={() => { setTopic(t); generateMemes(t); }} style={{
            background: "#1a0033", border: "1px solid #aa44ff66",
            color: "#aa44ff", padding: "5px 12px",
            borderRadius: 20, fontSize: 11,
            fontFamily: "monospace", cursor: "pointer"
          }}>
            {t}
          </button>
        ))}
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
        <input value={topic} onChange={e => setTopic(e.target.value)}
          placeholder="Custom topic..."
          style={{
            flex: 1, background: "#0a0a0a",
            border: "1px solid #aa44ff66", color: "#aa44ff",
            padding: "10px 12px", fontFamily: "monospace",
            fontSize: 13, borderRadius: 4, outline: "none"
          }} />
        <button onClick={() => generateMemes()} disabled={loading || !topic.trim()} style={{
          background: loading ? "#333" : "#aa44ff",
          border: "none", color: "#000",
          padding: "10px 20px", borderRadius: 4,
          fontFamily: "monospace", fontWeight: "bold",
          fontSize: 12, cursor: "pointer", textTransform: "uppercase"
        }}>
          {loading ? "FORGING..." : "FORGE"}
        </button>
      </div>

      {memes.map((m, i) => (
        <div key={i} style={{
          background: "#0d001a", border: "1px solid #aa44ff33",
          borderRadius: 8, padding: 16, marginBottom: 12
        }}>
          <div style={{ color: "#aa44ff88", fontSize: 10, fontFamily: "monospace", marginBottom: 8 }}>
            [{m.format}]
          </div>
          {m.top && <div style={{ color: "#fff", fontFamily: "monospace", fontSize: 14, fontWeight: "bold", marginBottom: 6 }}>"{m.top}"</div>}
          {m.bottom && <div style={{ color: "#ddd", fontFamily: "monospace", fontSize: 14 }}>"{m.bottom}"</div>}
          {m.boyfriend && (
            <div style={{ color: "#ddd", fontFamily: "monospace", fontSize: 12, lineHeight: 1.8 }}>
              <div>👦 <b>Boyfriend (you):</b> {m.boyfriend}</div>
              <div>👩 <b>Girlfriend (duty):</b> {m.girlfriend}</div>
              <div>💃 <b>Other girl:</b> {m.other_girl}</div>
            </div>
          )}
          {m.caption && <div style={{ color: "#fff", fontFamily: "monospace", fontSize: 14 }}>🔥 {m.caption}</div>}
        </div>
      ))}
    </div>
  );
}

